const fs = require('fs');
const items = $input.all();
for (let i = 0; i < items.length; i++) {
  try {
    // Intentar obtener de binario primero
    let buffer;
    try {
      buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    } catch (e) {
      // Si no hay binario, usar el body (si es texto)
      const content = items[i].json.body || items[i].json.query.content;
      buffer = Buffer.from(content);
    }

    const filePath = '/opt/RAG/implementacion_SARA/Ingesta_PDF_WEB.py';
    fs.writeFileSync(filePath, buffer);
    items[i].json.success = true;
    items[i].json.size = buffer.length;
  } catch (err) {
    items[i].json.success = false;
    items[i].json.error = err.message;
  }
}
return items;
